#include <stdio.h>
#include <inttypes.h>

// Function to print unsigned __int128
void print_uint128(__uint128_t x) {
    if (x == 0) { putchar('0'); return; }
    char buf[40]; int i = 0;
    while (x > 0) {
        buf[i++] = '0' + (x % 10);
        x /= 10;
    }
    while (i--) putchar(buf[i]);
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        unsigned long long n_ll, k_ll;
        scanf("%llu %llu", &n_ll, &k_ll);
        __uint128_t n = n_ll, k = k_ll;
        __uint128_t days = (n + k - 1) / k;
        print_uint128(days);
        if (T) putchar('\n');
    }
    return 0;
}

