#include <bits/stdc++.h>
using namespace std;

string toString(__uint128_t x) {
    if (x == 0) return "0";
    string s;
    while (x > 0) {
        s.push_back('0' + x % 10);
        x /= 10;
    }
    reverse(s.begin(), s.end());
    return s;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while (T--) {
        unsigned long long n_ll, k_ll; cin >> n_ll >> k_ll;
        __uint128_t n = n_ll, k = k_ll;
        __uint128_t days = (n + k - 1) / k;
        cout << toString(days);
        if (T) cout << '\n';
    }
    return 0;
}

